        processor.addProduct("Apple", 2.50);
        processor.addProduct("Banana", 1.75);

        String orderString = "Apple–2–3";
        int totalPrice = processor.calculateOrderPrice(orderString);
        System.out.println("Total Price: $" + totalPrice); // Output: Total Price: $8.75
    }
}
```

